import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getProperty } from '../../services/dataService';
import { formatCurrency, API_URL, formatDate } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { useAuth } from '../../context/AuthContext';
import { FiMapPin, FiHome, FiCalendar, FiBed, FiBath, FiMove3, FiParking, FiCheck } from 'react-icons/fi';

const PropertyDetails = () => {
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [property, setProperty] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedImage, setSelectedImage] = useState(0);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getProperty(id);
        setProperty(res.data.data);
      } catch (err) { navigate('/properties'); }
      finally { setLoading(false); }
    };
    fetch();
  }, [id, navigate]);

  if (loading) return <LoadingSpinner />;
  if (!property) return null;

  return (
    <div style={{ background: '#f8f9fa', minHeight: '100vh', paddingBottom: '60px' }}>
      {/* Hero Section */}
      <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '0' }}>
        {/* Header */}
        <div style={{
          background: 'white',
          padding: '24px',
          borderBottom: '1px solid #e0e0e0',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <div>
            <h1 style={{ margin: '0 0 8px 0', fontSize: '32px', fontWeight: '700', color: '#1a1a1a' }}>
              {property.title}
            </h1>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#666', fontSize: '14px' }}>
              <FiMapPin size={18} />
              <span>{property.location?.address}, {property.location?.city}, {property.location?.state}</span>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <StatusBadge status={property.status} />
            {property.status === 'available' && user && user.role === 'customer' && (
              <Link to={`/customer/purchase-requests/new/${property._id}`} 
                style={{
                  padding: '10px 20px',
                  background: '#007bff',
                  color: 'white',
                  borderRadius: '6px',
                  textDecoration: 'none',
                  fontWeight: '600',
                  fontSize: '14px',
                  cursor: 'pointer',
                  border: 'none',
                  transition: 'all 0.3s'
                }}
                onMouseOver={(e) => e.target.style.background = '#0056b3'}
                onMouseOut={(e) => e.target.style.background = '#007bff'}
              >
                Request Purchase
              </Link>
            )}
            {!user && property.status === 'available' && (
              <Link to="/login" 
                style={{
                  padding: '10px 20px',
                  background: '#007bff',
                  color: 'white',
                  borderRadius: '6px',
                  textDecoration: 'none',
                  fontWeight: '600',
                  fontSize: '14px',
                  cursor: 'pointer',
                  border: 'none',
                  transition: 'all 0.3s'
                }}
                onMouseOver={(e) => e.target.style.background = '#0056b3'}
                onMouseOut={(e) => e.target.style.background = '#007bff'}
              >
                Login to Purchase
              </Link>
            )}
          </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '24px', padding: '24px' }}>
          {/* Main Content */}
          <div>
            {/* Image Gallery */}
            <div style={{
              background: 'white',
              borderRadius: '12px',
              overflow: 'hidden',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              marginBottom: '24px'
            }}>
              <div style={{
                height: '500px',
                background: '#f0f0f0',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                position: 'relative',
                overflow: 'hidden'
              }}>
                {property.images && property.images.length > 0 ? (
                  <img src={`${API_URL}${property.images[selectedImage]}`} alt={property.title}
                    style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <div style={{ fontSize: '120px', opacity: 0.2 }}>🏠</div>
                )}
              </div>

              {/* Thumbnail Gallery */}
              {property.images && property.images.length > 1 && (
                <div style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fill, minmax(100px, 1fr))',
                  gap: '8px',
                  padding: '16px',
                  background: '#fafafa'
                }}>
                  {property.images.map((img, i) => (
                    <div
                      key={i}
                      onClick={() => setSelectedImage(i)}
                      style={{
                        height: '80px',
                        borderRadius: '6px',
                        overflow: 'hidden',
                        cursor: 'pointer',
                        border: i === selectedImage ? '3px solid #007bff' : '2px solid #ddd',
                        transition: 'all 0.3s',
                        background: '#f0f0f0'
                      }}
                      onMouseOver={(e) => {
                        if (i !== selectedImage) e.currentTarget.style.borderColor = '#007bff';
                      }}
                      onMouseOut={(e) => {
                        if (i !== selectedImage) e.currentTarget.style.borderColor = '#ddd';
                      }}
                    >
                      <img src={`${API_URL}${img}`} alt={`${i + 1}`}
                        style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Description */}
            <div style={{
              background: 'white',
              borderRadius: '12px',
              padding: '24px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              marginBottom: '24px'
            }}>
              <h3 style={{ margin: '0 0 16px 0', fontSize: '20px', fontWeight: '700', color: '#1a1a1a' }}>
                About this property
              </h3>
              <p style={{ fontSize: '15px', lineHeight: '1.8', color: '#555', margin: 0 }}>
                {property.description}
              </p>
            </div>

            {/* Features Grid */}
            <div style={{
              background: 'white',
              borderRadius: '12px',
              padding: '24px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              marginBottom: '24px'
            }}>
              <h3 style={{ margin: '0 0 20px 0', fontSize: '20px', fontWeight: '700', color: '#1a1a1a' }}>
                Features
              </h3>
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
                gap: '16px'
              }}>
                <div style={{
                  padding: '16px',
                  background: '#f8f9fa',
                  borderRadius: '8px',
                  textAlign: 'center',
                  borderLeft: '4px solid #007bff'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px' }}>
                    <FiBed size={28} color='#007bff' />
                  </div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>Bedrooms</p>
                  <p style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#1a1a1a' }}>
                    {property.features?.bedrooms || 0}
                  </p>
                </div>

                <div style={{
                  padding: '16px',
                  background: '#f8f9fa',
                  borderRadius: '8px',
                  textAlign: 'center',
                  borderLeft: '4px solid #28a745'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px' }}>
                    <FiBath size={28} color='#28a745' />
                  </div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>Bathrooms</p>
                  <p style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#1a1a1a' }}>
                    {property.features?.bathrooms || 0}
                  </p>
                </div>

                <div style={{
                  padding: '16px',
                  background: '#f8f9fa',
                  borderRadius: '8px',
                  textAlign: 'center',
                  borderLeft: '4px solid #ffc107'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px' }}>
                    <FiMove3 size={28} color='#ffc107' />
                  </div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>Area</p>
                  <p style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#1a1a1a' }}>
                    {(property.features?.area || 0).toLocaleString()} sqft
                  </p>
                </div>

                <div style={{
                  padding: '16px',
                  background: '#f8f9fa',
                  borderRadius: '8px',
                  textAlign: 'center',
                  borderLeft: '4px solid #dc3545'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px' }}>
                    <FiParking size={28} color='#dc3545' />
                  </div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>Parking</p>
                  <p style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#1a1a1a' }}>
                    {property.features?.parking ? 'Yes' : 'No'}
                  </p>
                </div>

                <div style={{
                  padding: '16px',
                  background: '#f8f9fa',
                  borderRadius: '8px',
                  textAlign: 'center',
                  borderLeft: '4px solid #17a2b8'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '8px' }}>
                    <FiCheck size={28} color='#17a2b8' />
                  </div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#666', textTransform: 'uppercase' }}>Furnished</p>
                  <p style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#1a1a1a' }}>
                    {property.features?.furnished ? 'Yes' : 'No'}
                  </p>
                </div>
              </div>
            </div>

            {/* Location Section */}
            <div style={{
              background: 'white',
              borderRadius: '12px',
              padding: '24px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
            }}>
              <h3 style={{ margin: '0 0 20px 0', fontSize: '20px', fontWeight: '700', color: '#1a1a1a' }}>
                Location Details
              </h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
                <div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase', fontWeight: '600' }}>
                    Address
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500' }}>
                    {property.location?.address}
                  </p>
                </div>
                <div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase', fontWeight: '600' }}>
                    City
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500' }}>
                    {property.location?.city}
                  </p>
                </div>
                <div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase', fontWeight: '600' }}>
                    State
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500' }}>
                    {property.location?.state}
                  </p>
                </div>
                {property.location?.zipCode && (
                  <div>
                    <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase', fontWeight: '600' }}>
                      Zip Code
                    </p>
                    <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500' }}>
                      {property.location.zipCode}
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div>
            {/* Price Card */}
            <div style={{
              background: 'linear-gradient(135deg, #007bff 0%, #0056b3 100%)',
              borderRadius: '12px',
              padding: '24px',
              color: 'white',
              boxShadow: '0 4px 12px rgba(0, 123, 255, 0.3)',
              marginBottom: '20px',
              textAlign: 'center'
            }}>
              <p style={{ margin: '0 0 8px 0', fontSize: '12px', textTransform: 'uppercase', opacity: 0.9 }}>
                Property Price
              </p>
              <p style={{ margin: 0, fontSize: '36px', fontWeight: '700' }}>
                {formatCurrency(property.price)}
              </p>
            </div>

            {/* Key Info Card */}
            <div style={{
              background: 'white',
              borderRadius: '12px',
              padding: '24px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              marginBottom: '20px'
            }}>
              <h4 style={{ margin: '0 0 16px 0', fontSize: '16px', fontWeight: '700', color: '#1a1a1a' }}>
                Property Info
              </h4>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div style={{ paddingBottom: '12px', borderBottom: '1px solid #eee' }}>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase' }}>
                    Type
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500', textTransform: 'capitalize' }}>
                    {property.type}
                  </p>
                </div>
                <div style={{ paddingBottom: '12px', borderBottom: '1px solid #eee' }}>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase' }}>
                    Status
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500', textTransform: 'capitalize' }}>
                    {property.status}
                  </p>
                </div>
                <div>
                  <p style={{ margin: '0 0 4px 0', fontSize: '12px', color: '#999', textTransform: 'uppercase' }}>
                    Listed
                  </p>
                  <p style={{ margin: 0, fontSize: '15px', color: '#1a1a1a', fontWeight: '500' }}>
                    {formatDate(property.createdAt)}
                  </p>
                </div>
              </div>
            </div>

            {/* CTA Card */}
            {property.status === 'available' && (
              <div style={{
                background: '#f8f9fa',
                borderRadius: '12px',
                padding: '20px',
                textAlign: 'center',
                border: '2px dashed #007bff'
              }}>
                <p style={{ margin: '0 0 16px 0', fontSize: '14px', color: '#666' }}>
                  Interested in this property?
                </p>
                {user && user.role === 'customer' ? (
                  <Link to={`/customer/purchase-requests/new/${property._id}`}
                    style={{
                      display: 'inline-block',
                      width: '100%',
                      padding: '12px',
                      background: '#007bff',
                      color: 'white',
                      borderRadius: '6px',
                      textDecoration: 'none',
                      fontWeight: '600',
                      fontSize: '14px',
                      cursor: 'pointer',
                      border: 'none',
                      transition: 'all 0.3s',
                      textAlign: 'center'
                    }}
                    onMouseOver={(e) => e.target.style.background = '#0056b3'}
                    onMouseOut={(e) => e.target.style.background = '#007bff'}
                  >
                    Make a Request
                  </Link>
                ) : (
                  <Link to="/login"
                    style={{
                      display: 'inline-block',
                      width: '100%',
                      padding: '12px',
                      background: '#007bff',
                      color: 'white',
                      borderRadius: '6px',
                      textDecoration: 'none',
                      fontWeight: '600',
                      fontSize: '14px',
                      cursor: 'pointer',
                      border: 'none',
                      transition: 'all 0.3s',
                      textAlign: 'center'
                    }}
                    onMouseOver={(e) => e.target.style.background = '#0056b3'}
                    onMouseOut={(e) => e.target.style.background = '#007bff'}
                  >
                    Login First
                  </Link>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PropertyDetails;
